export type AppDeps = ClaimControllerDeps & DisputeControllerDeps;

export function buildApp(deps: AppDeps): FastifyInstance {
  const app = Fastify({ logger: false });

  registerErrorHandler(app);
  registerClaimRoutes(app, deps);

  return app;
}

