1	// app/src/services/claim.service.ts — orchestration: submit claim -> adjudicate -> persist.
2	//
3	// A SERVICE holds business logic / workflows; it depends on REPOSITORIES (which own the Db and
4	// encapsulate all data access), never on the raw connection. Layering: service → repositories → db.
5	// Every status change routes through the injected setStatus() chokepoint (status column + transition
6	// log in one write). The one-transaction-per-claim boundary is an injected withTransaction runner.
7	
8	import { adjudicateLine } from "../domain/adjudication/adjudicator";
9	import type { ClaimStatus } from "../domain/entities/claim";
10	import {
11	  type LineOutcome,
12	  aggregateClaimStatus,
13	} from "../domain/state-machines/claim-state";
14	import type { AccumulatorRepository } from "../repositories/accumulator.repository";
15	import type { AdjudicationRepository } from "../repositories/adjudication.repository";
16	import type { ClaimRepository } from "../repositories/claim.repository";
17	import type { CoverageRuleRepository } from "../repositories/coverage-rule.repository";
18	import type { PolicyRepository } from "../repositories/policy.repository";
19	import type { SetStatus } from "./set-status";
20	
21	export type ClaimServiceDeps = {
22	  claims: ClaimRepository;
23	  adjudications: AdjudicationRepository;
24	  accumulators: AccumulatorRepository;
25	  coverageRules: CoverageRuleRepository;
26	  policies: PolicyRepository;
27	  setStatus: SetStatus;
28	  withTransaction: <T>(fn: () => T) => T;
29	};
30	
31	export type AdjudicateClaimInput = {
32	  memberId: string;
33	  serviceDate: string;
34	  provider?: string;
35	  diagnosisCode?: string;
36	  lineItems: {
37	    serviceCode: string;
38	    billedCents: number;
39	    units?: number;
40	    priorAuthPresent?: boolean;
41	  }[];
42	};
43	
44	export type AdjudicateClaimResult = { claimId: string; status: ClaimStatus };
45	
46	// An intake identity failure (4xx) — distinct from an adjudication decision (HTTP 200). Thrown when
47	// a claim cannot be resolved to a member's policy at all; the controller maps it to a 400 reject.
48	export class ClaimIntakeError extends Error {
49	  readonly field: string;
50	  readonly code: string;
51	  constructor(field: string, code: string, message: string) {
52	    super(message);
53	    this.name = "ClaimIntakeError";
54	    this.field = field;
55	    this.code = code;
56	  }
57	}
58	
59	export function createClaimService(deps: ClaimServiceDeps) {
60	  function adjudicateClaim(input: AdjudicateClaimInput): AdjudicateClaimResult {
61	    return deps.withTransaction(() => {
62	      // Resolve the member's policy WITHOUT a date filter: an out-of-window date is a
63	      // POLICY_NOT_ACTIVE decision (the adjudicator's first gate), not an intake reject. Only a
64	      // member with no policy on file is unresolvable.
65	      const policy = deps.policies.findByMember(input.memberId);
66	      if (!policy) {
67	        throw new ClaimIntakeError(
68	          "memberId",
69	          "MEMBER_NOT_FOUND",
70	          `no policy on file for member ${input.memberId}`,
71	        );
72	      }
73	      const planYear = String(policy.planYear);
74	      const ruleByService = new Map(
75	        deps.coverageRules
76	          .findByPolicy(policy.id)
77	          .map((r) => [r.serviceCode, r]),
78	      );
79	
80	      const claimId = deps.claims.insertClaim({
81	        memberId: input.memberId,
82	        policyId: policy.id,
83	        serviceDate: input.serviceDate,
84	        provider: input.provider ?? null,
85	        diagnosisCode: input.diagnosisCode ?? null,
86	      });
87	      deps.setStatus({
88	        claimId,
89	        target: { type: "CLAIM", status: "SUBMITTED" },
90	        fromStatus: null,
91	        actor: "SYSTEM",
92	        reason: "SUBMIT",
93	      });
94	
95	      // Phase 1 — persist + submit every line (PENDING).
96	      const submitted = input.lineItems.map((li) => {
97	        const fingerprint = `${input.memberId}|${li.serviceCode}|${input.serviceDate}|${li.billedCents}`;
98	        const line = deps.claims.insertLine(claimId, {
99	          serviceCode: li.serviceCode,
100	          billedCents: li.billedCents,
101	          units: li.units,
102	          priorAuthPresent: li.priorAuthPresent,
103	          fingerprint,
104	        });
105	        deps.setStatus({
106	          claimId,
107	          target: { type: "LINE_ITEM", id: line.id, status: "PENDING" },
108	          fromStatus: null,
109	          actor: "SYSTEM",
110	          reason: "SUBMIT",
111	        });
112	        return { line, fingerprint };
113	      });
114	
115	      // Phase 2 — adjudicate each line in order. One snapshot at claim start; deltas are applied to
116	      // this working copy between lines so a later line sees an earlier line's draw (determinism).
117	      const acc = deps.accumulators.snapshot(input.memberId, planYear);
118	      const touched = {
119	        deductible: false,
120	        oop: false,
121	        limits: new Set<string>(),
122	      };
123	      const outcomes: LineOutcome[] = [];
124	
125	      for (const { line, fingerprint } of submitted) {
126	        const result = adjudicateLine({
127	          line: {
128	            id: line.id,
129	            claimId,
130	            serviceCode: line.serviceCode,
131	            billedCents: line.billedCents,
132	            units: line.units,
133	            priorAuthPresent: line.priorAuthPresent,
134	            status: "PENDING",
135	            fingerprint,
136	          },
137	          policy,
138	          rule: ruleByService.get(line.serviceCode),
139	          serviceDate: input.serviceDate,
140	          acc: {
141	            deductibleMetCents: acc.deductibleMetCents,
142	            oopMetCents: acc.oopMetCents,
143	            limitUsed: acc.limitUsedByService[line.serviceCode] ?? 0,
144	          },
145	          alreadyAdjudicated: false,
146	        });
147	
148	        // adjudicateLine only ever decides APPROVED | DENIED (never PENDING/NEEDS_REVIEW)
149	        const newStatus = result.status as "APPROVED" | "DENIED";
150	        deps.adjudications.append({
151	          lineItemId: line.id,
152	          planYear,
153	          seq: 1, // first decision for this line; a dispute re-adjudication appends a higher seq
154	          status: newStatus,
155	          billedCents: line.billedCents,
156	          payableCents: result.payableCents,
157	          memberResponsibilityCents: result.memberResponsibilityCents,
158	          reasons: result.reasons,
159	          explanation: result.explanation,
160	          deltas: result.deltas,
161	        });
162	        deps.setStatus({
163	          claimId,
164	          target: { type: "LINE_ITEM", id: line.id, status: newStatus },
165	          fromStatus: "PENDING",
166	          actor: "SYSTEM",
167	          reason: "ADJUDICATED",
168	        });
169	
170	        if (result.deltas.deductibleIncCents > 0) {
171	          acc.deductibleMetCents += result.deltas.deductibleIncCents;
172	          touched.deductible = true;
173	        }
174	        if (result.deltas.oopIncCents > 0) {
175	          acc.oopMetCents += result.deltas.oopIncCents;
176	          touched.oop = true;
177	        }
178	        if (result.deltas.limitInc > 0) {
179	          acc.limitUsedByService[line.serviceCode] =
180	            (acc.limitUsedByService[line.serviceCode] ?? 0) +
181	            result.deltas.limitInc;
182	          touched.limits.add(line.serviceCode);
183	        }
184	
185	        outcomes.push({ status: newStatus, reasons: result.reasons });
186	      }
187	
