1	// app/src/services/dispute.service.ts — orchestration: open dispute -> re-adjudicate, preserve original.
2	//
3	// A SERVICE holds business logic / workflows; it depends on REPOSITORIES (which own the Db), never on
4	// the raw connection. Layering: service → repositories → db. Every status change routes through the
5	// injected setStatus() chokepoint.
6	//
7	// A dispute is synchronous (open → re-adjudicate → resolve, one transaction). It re-adjudicates the
8	// disputed line against CURRENT rules + corrected facts and a working snapshot of
9	// `current accumulator − this line's own original deltas` (net-out — decision #16), APPENDS a new
10	// immutable decision (the original is preserved), and resolves to a 4-value outcome. Guards: a
11	// missing line → NOT_FOUND (404); a non-terminal line → CONFLICT (409).
12	
13	import { adjudicateLine } from "../domain/adjudication/adjudicator";
14	import type { ReasonCode } from "../domain/reason-codes";
15	import { aggregateClaimStatus } from "../domain/state-machines/claim-state";
16	import type { AccumulatorRepository } from "../repositories/accumulator.repository";
17	import type { AdjudicationRepository } from "../repositories/adjudication.repository";
18	import type { ClaimRepository } from "../repositories/claim.repository";
19	import type { CoverageRuleRepository } from "../repositories/coverage-rule.repository";
20	import type {
21	  CorrectedFacts,
22	  DisputeOutcome,
23	  DisputeRepository,
24	} from "../repositories/dispute.repository";
25	import type { PolicyRepository } from "../repositories/policy.repository";
26	import type { SetStatus } from "./set-status";
27	
28	export type DisputeErrorCode = "NOT_FOUND" | "CONFLICT";
29	
30	// A dispute identity/state failure (4xx) — distinct from an adjudication decision (HTTP 200).
31	export class DisputeError extends Error {
32	  readonly code: DisputeErrorCode;
33	  constructor(code: DisputeErrorCode, message: string) {
34	    super(message);
35	    this.code = code;
36	    this.name = "DisputeError";
37	  }
38	}
39	
40	export type DisputeServiceDeps = {
41	  claims: ClaimRepository;
42	  adjudications: AdjudicationRepository;
43	  accumulators: AccumulatorRepository;
44	  coverageRules: CoverageRuleRepository;
45	  policies: PolicyRepository;
46	  disputes: DisputeRepository;
47	  setStatus: SetStatus;
48	  withTransaction: <T>(fn: () => T) => T;
49	};
50	
51	export type OpenDisputeInput = {
52	  lineItemId: string;
53	  reason: string;
54	  corrected?: CorrectedFacts | undefined;
55	};
56	
57	export type OpenDisputeResult = {
58	  disputeId: string;
59	  outcome: DisputeOutcome;
60	  originalAdjudicationId: string;
61	  resolvedAdjudicationId: string;
62	};
63	
64	type Decision = {
65	  status: "APPROVED" | "DENIED";
66	  payableCents: number;
67	  reasons: ReasonCode[];
68	};
69	
70	// Diff the new decision against the original (decision #16 outcome taxonomy).
71	function diffOutcome(original: Decision, next: Decision): DisputeOutcome {
72	  if (original.status === "DENIED" && next.status === "APPROVED") {
73	    return next.reasons.includes("LIMIT_EXCEEDED")
74	      ? "PARTIALLY_OVERTURNED"
75	      : "OVERTURNED";
76	  }
77	  const unchanged =
78	    original.status === next.status &&
79	    original.payableCents === next.payableCents &&
80	    JSON.stringify(original.reasons) === JSON.stringify(next.reasons);
81	  return unchanged ? "UPHELD" : "MODIFIED";
82	}
83	
84	export function createDisputeService(deps: DisputeServiceDeps) {
85	  function open(input: OpenDisputeInput): OpenDisputeResult {
86	    return deps.withTransaction(() => {
87	      const line = deps.claims.findLineById(input.lineItemId);
88	      if (!line) {
89	        throw new DisputeError(
90	          "NOT_FOUND",
91	          `line item not found: ${input.lineItemId}`,
92	        );
93	      }
94	      // Only a terminal line is disputable (decision #16); PENDING / NEEDS_REVIEW → 409.
95	      if (line.status !== "APPROVED" && line.status !== "DENIED") {
96	        throw new DisputeError(
97	          "CONFLICT",
98	          `line ${input.lineItemId} is not in a terminal state (${line.status})`,
99	        );
100	      }
101	      const original = deps.adjudications.currentForLine(input.lineItemId);
102	      if (!original) {
103	        throw new DisputeError(
104	          "NOT_FOUND",
105	          `no adjudication to dispute for line ${input.lineItemId}`,
106	        );
107	      }
108	
109	      const claim = deps.claims.findClaimById(line.claimId);
110	      if (!claim)
111	        throw new DisputeError("NOT_FOUND", `claim not found: ${line.claimId}`);
112	      const policy = deps.policies.findActiveForMember(
113	        claim.memberId,
114	        claim.serviceDate,
115	      );
116	      if (!policy) {
117	        throw new Error(
118	          `no active policy for member ${claim.memberId} on ${claim.serviceDate}`,
119	        );
120	      }
121	      const planYear = String(policy.planYear);
122	      const ruleByService = new Map(
123	        deps.coverageRules
124	          .findByPolicy(policy.id)
125	          .map((r) => [r.serviceCode, r]),
126	      );
127	
128	      // Reopen: the terminal line moves to NEEDS_REVIEW, initiated by the MEMBER.
129	      deps.setStatus({
130	        claimId: claim.id,
131	        target: { type: "LINE_ITEM", id: line.id, status: "NEEDS_REVIEW" },
132	        fromStatus: original.status,
133	        actor: "MEMBER",
134	        reason: "DISPUTE_REOPEN",
135	      });
136	
137	      // Overlay the corrected facts (the only amendable line fields).
138	      const corrected = input.corrected ?? {};
139	      const origService = line.serviceCode;
140	      const effServiceCode = corrected.serviceCode ?? line.serviceCode;
141	      const effBilledCents = corrected.billedCents ?? line.billedCents;
142	      const effUnits = corrected.units ?? line.units;
143	      const effPriorAuth = corrected.priorAuthPresent ?? line.priorAuthPresent;
144	
145	      // Net-out: re-adjudicate against `current accumulator − this line's own original deltas`, so
146	      // the disputed line contributes exactly once (at its newest decision). Invariant: each
147	      // dimension = Σ of every line's latest deltas — the deductible never double-counts.
148	      const acc = deps.accumulators.snapshot(claim.memberId, planYear);
149	      const od = original.deltas;
150	      const nettedDeductible = acc.deductibleMetCents - od.deductibleIncCents;
151	      const nettedOop = acc.oopMetCents - od.oopIncCents;
152	      const nettedLimitOrig =
153	        (acc.limitUsedByService[origService] ?? 0) - od.limitInc;
154	      const nettedLimitEff =
155	        effServiceCode === origService
156	          ? nettedLimitOrig
157	          : (acc.limitUsedByService[effServiceCode] ?? 0);
158	
159	      const result = adjudicateLine({
160	        line: {
161	          id: line.id,
162	          claimId: line.claimId,
163	          serviceCode: effServiceCode,
164	          billedCents: effBilledCents,
165	          units: effUnits,
166	          priorAuthPresent: effPriorAuth,
167	          status: "PENDING",
168	          fingerprint: line.fingerprint,
169	        },
170	        policy,
171	        rule: ruleByService.get(effServiceCode),
172	        serviceDate: claim.serviceDate,
173	        acc: {
174	          deductibleMetCents: nettedDeductible,
175	          oopMetCents: nettedOop,
176	          limitUsed: nettedLimitEff,
177	        },
178	        alreadyAdjudicated: false,
179	      });
180	      const nd = result.deltas;
181	
182	      // Append the NEW decision at a higher seq — the original row is never touched (append-only).
183	      const newStatus = result.status as "APPROVED" | "DENIED";
184	      const resolvedAdjudicationId = deps.adjudications.append({
185	        lineItemId: input.lineItemId,
186	        planYear,
187	        seq: original.seq + 1,
188	        status: newStatus,
189	        billedCents: effBilledCents,
190	        payableCents: result.payableCents,
191	        memberResponsibilityCents: result.memberResponsibilityCents,
192	        reasons: result.reasons,
193	        explanation: result.explanation,
194	        deltas: nd,
195	      });
196	      // Auto re-adjudication clears NEEDS_REVIEW back to a terminal line state.
197	      deps.setStatus({
198	        claimId: claim.id,
199	        target: { type: "LINE_ITEM", id: line.id, status: newStatus },
200	        fromStatus: "NEEDS_REVIEW",
201	        actor: "SYSTEM",
202	        reason: "ADJUDICATED",
203	      });
204	
205	      // Write back the net-out: final = (current − original deltas) + new deltas, per touched dimension.
206	      const limitUnitOf = (svc: string): "CENTS" | "COUNT" =>
207	        ruleByService.get(svc)?.limit.unit === "visits" ? "COUNT" : "CENTS";
208	      if (od.deductibleIncCents > 0 || nd.deductibleIncCents > 0) {
209	        deps.accumulators.upsert({
210	          memberId: claim.memberId,
211	          planYear,
212	          dimension: "DEDUCTIBLE",
213	          unit: "CENTS",
214	          usedCents: nettedDeductible + nd.deductibleIncCents,
215	          usedCount: 0,
216	        });
217	      }
218	      if (od.oopIncCents > 0 || nd.oopIncCents > 0) {
219	        deps.accumulators.upsert({
220	          memberId: claim.memberId,
221	          planYear,
222	          dimension: "OOP",
223	          unit: "CENTS",
224	          usedCents: nettedOop + nd.oopIncCents,
225	          usedCount: 0,
